static serdes_schema_t *load_schema (const char *name, const char *path) {
        serdes_schema_t *schema;
        FILE *fp;
        char *buf;
        long size;
        char errstr[256];

        if (!(fp = fopen(path, "r")))
                KC_FATAL("Failed to open schema file %s: %s",
                         path, strerror(errno));

        fseek(fp, 0, SEEK_END);
        size = ftell(fp);
        fseek(fp, 0, SEEK_SET);

        if (size <= 0)
                KC_FATAL("Schema file %s is too small: %ld", path, size);

        buf = malloc(size+1);
        if (!buf)
                KC_FATAL("Failed to allocate buffer for %s of %ld bytes: %s",
                         path, size, strerror(errno));

        if (fread(buf, size, 1, fp) != 1)
                KC_FATAL("Failed to read schema file %s: %s",
                         path, strerror(errno));

        fclose(fp);

        buf[size] = '\0';

        schema = serdes_schema_add(serdes, name, -1, buf, (int)size,
                                   errstr, sizeof(errstr));
        if (!schema)
                KC_FATAL("Failed parse schema file %s: %s", path, errstr);

        return schema;
}

void kc_avro_init (const char *key_schema_name,
                   const char *key_schema_path,
                   const char *value_schema_name,
                   const char *value_schema_path) {
        char errstr[512];

        serdes = serdes_new(conf.srconf, errstr, sizeof(errstr));
        if (!serdes)
                KC_FATAL("Failed to create schema-registry client: %s", errstr);
        conf.srconf = NULL;

        if (key_schema_path)
                key_schema = load_schema(key_schema_name,
                                         key_schema_path);

        if (value_schema_path)
                value_schema = load_schema(value_schema_name,
                                           value_schema_path);

}

void kc_avro_term (void) {
        if (value_schema)
                serdes_schema_destroy(value_schema);
        if (key_schema)
                serdes_schema_destroy(key_schema);
        if (serdes)
                serdes_destroy(serdes);
}

char *kc_avro_to_json (const void *data, size_t data_len, int *schema_idp,
                       char *errstr, size_t errstr_size) {
        avro_value_t avro;
        serdes_schema_t *schema;
        char *json;
        serdes_err_t err;

        err = serdes_deserialize_avro(serdes, &avro, &schema, data, data_len,
                                      errstr, errstr_size);
        if (err) {
                if (err == SERDES_ERR_FRAMING_INVALID ||
                    strstr(errstr, "Invalid CP1 magic byte")) {
                        static const char badframing[] =
                                ": message not produced with "
                                "Schema-Registry Avro framing";
                        int len = strlen(errstr);

                        if (len + sizeof(badframing) < errstr_size)
                                snprintf(errstr+len, errstr_size-len,
                                         "%s", badframing);
                }
                return NULL;
        }

        if (avro_value_to_json(&avro, 1/*one-line*/, &json)) {
                snprintf(errstr, errstr_size, "Failed to encode Avro as JSON");
                avro_value_decref(&avro);
                return NULL;
        }

        if (schema && schema_idp)
                *schema_idp = serdes_schema_id(schema);

        avro_value_decref(&avro);

        return json;
}

static void fmt_add (fmt_type_t type, const char *str, int len) {
        if (conf.fmt_cnt == KC_FMT_MAX_SIZE)
                KC_FATAL("Too many formatters & strings (KC_FMT_MAX_SIZE=%i)",
                         KC_FMT_MAX_SIZE);

        conf.fmt[conf.fmt_cnt].type = type;

        /* For STR types */
        if (len) {
                const char *s;
                char *d;
                conf.fmt[conf.fmt_cnt].str = d = malloc(len+1);
                memcpy(d, str, len);
                d[len] = '\0';
                s = d;

                /* Convert \.. sequences */
                while (*s) {
                        if (*s == '\\' && *(s+1)) {
                                int base = 0;
                                const char *next;
                                s++;
                                switch (*s) {
                                case 't':
                                        *d = '\t';
                                        break;
                                case 'n':
                                        *d = '\n';
                                        break;
                                case 'r':
                                        *d = '\r';
                                        break;
                                case 'x':
                                        s++;
                                        base = 16;
                                        /* FALLTHRU */
                                default:
                                        if (*s >= '0' && *s <= '9') {
                                                *d = (char)strtoul(
                                                        s, (char **)&next,
                                                        base);
                                                if (next > s)
                                                        s = next - 1;
                                        } else {
                                                *d = *s;
                                        }
                                        break;
                                }
                        } else {
                                *d = *s;
                        }
                        s++;
                        d++;
                }

                *d = '\0';

                conf.fmt[conf.fmt_cnt].str_len =
                        strlen(conf.fmt[conf.fmt_cnt].str);
        }

        conf.fmt_cnt++;
}

void fmt_parse (const char *fmt) {
        const char *s = fmt, *t;

        while (*s) {
                if ((t = strchr(s, '%'))) {
                        if (t > s)
                                fmt_add(KC_FMT_STR, s, (int)(t-s));

                        s = t+1;
                        switch (*s)
                        {
                        case 'o':
                                fmt_add(KC_FMT_OFFSET, NULL, 0);
                                break;
                        case 'k':
                                fmt_add(KC_FMT_KEY, NULL, 0);
                                break;
                        case 'K':
                                fmt_add(KC_FMT_KEY_LEN, NULL, 0);
                                break;
                        case 's':
                                fmt_add(KC_FMT_PAYLOAD, NULL, 0);
                                break;
                        case 'S':
                                fmt_add(KC_FMT_PAYLOAD_LEN, NULL, 0);
                                break;
                        case 'R':
                                fmt_add(KC_FMT_PAYLOAD_LEN_BINARY, NULL, 0);
                                break;
                        case 't':
                                fmt_add(KC_FMT_TOPIC, NULL, 0);
                                break;
                        case 'p':
                                fmt_add(KC_FMT_PARTITION, NULL, 0);
                                break;
                        case 'T':
                                fmt_add(KC_FMT_TIMESTAMP, NULL, 0);
                                conf.flags |= CONF_F_APIVERREQ;
                                break;
#if HAVE_HEADERS
                        case 'h':
                                fmt_add(KC_FMT_HEADERS, NULL, 0);
                                conf.flags |= CONF_F_APIVERREQ;
                                break;
#endif
                        case '%':
                                fmt_add(KC_FMT_STR, s, 1);
                                break;
                        case '\0':
                                KC_FATAL("Empty formatter");
                                break;
                        default:
                                KC_FATAL("Unsupported formatter: %%%c", *s);
                                break;
                        }
                        s++;
                } else {
                        fmt_add(KC_FMT_STR, s, strlen(s));
                        break;
                }

        }
}

void fmt_init (void) {
#if ENABLE_JSON
        if (conf.flags & CONF_F_FMT_JSON)
                fmt_init_json();
#endif
}

void fmt_term (void) {
#if ENABLE_JSON
        if (conf.flags & CONF_F_FMT_JSON)
                fmt_term_json();
#endif
}

static int print_headers (FILE *fp, const rd_kafka_headers_t *hdrs) {
        size_t idx = 0;
        const char *name;
        const void *value;
        size_t size;

        while (!rd_kafka_header_get_all(hdrs, idx++, &name, &value, &size)) {
                fprintf(fp, "%s%s=", idx > 1 ? "," : "", name);
                if (value && size > 0)
                        fprintf(fp, "%.*s", (int)size, (const char *)value);
                else if (!value)
                        fprintf(fp, "NULL");
        }
        return 1;
}

void pack_check (const char *what, const char *fmt) {
        const char *f = fmt;
        static const char *valid = " <>bBhHiIqQcs$";

        if (!*fmt)
                KC_FATAL("%s pack-format must not be empty", what);

        while (*f) {
                if (!strchr(valid, (int)(*f)))
                        KC_FATAL("Invalid token '%c' in %s pack-format, "
                                 "see -s usage.",
                                 (int)(*f), what);
                f++;
        }
}

static int unpack (FILE *fp, const char *what, const char *fmt,
                   const char *buf, size_t len,
                   char *errstr, size_t errstr_size) {
        const char *b = buf;
        const char *end = buf+len;
        const char *f = fmt;
        enum {
                big_endian,
                little_endian
        } endian = big_endian;

#define endian_swap(val,to_little,to_big)                       \
        (endian == big_endian ? to_big(val) : to_little(val))

#define fup_copy(dst,sz) do {                                           \
                if ((sz) > remaining) {                                 \
                        snprintf(errstr, errstr_size,                   \
                                 "%s truncated, expected %d bytes "     \
                                 "to unpack %c but only %d bytes remaining", \
                                 what, (int)(sz), (int)(*f),            \
                                 (int)remaining);                       \
                        return -1;                                      \
                }                                                       \
                memcpy(dst, b, sz);                                     \
                b += (sz);                                              \
        } while (0)

        while (*f) {
                size_t remaining = (int)(end - b);

                switch ((int)*f)
                {
                case ' ':
                        fprintf(fp, " ");
                        break;
                case '<':
                        endian = little_endian;
                        break;
                case '>':
                        endian = big_endian;
                        break;
                case 'b':
                {
                        int8_t v;
                        fup_copy(&v, sizeof(v));
                        fprintf(fp, "%d", (int)v);
                }
                break;
                case 'B':
                {
                        uint8_t v;
                        fup_copy(&v, sizeof(v));
                        fprintf(fp, "%u", (unsigned int)v);
                }
                break;
                case 'h':
                {
                        int16_t v;
                        fup_copy(&v, sizeof(v));
                        v = endian_swap(v, be16toh, be16toh);
                        fprintf(fp, "%hd", v);
                }
                break;
                case 'H':
                {
                        uint16_t v;
                        fup_copy(&v, sizeof(v));
                        v = endian_swap(v, be16toh, be16toh);
                        fprintf(fp, "%hu", v);
                }
                break;
                case 'i':
                {
                        int32_t v;
                        fup_copy(&v, sizeof(v));
                        v = endian_swap(v, be32toh, htobe32);
                        fprintf(fp, "%d", v);
                }
                break;
                case 'I':
                {
                        uint32_t v;
                        fup_copy(&v, sizeof(v));
                        v = endian_swap(v, be32toh, htobe32);
                        fprintf(fp, "%u", v);
                }
                break;
                case 'q':
                {
                        int64_t v;
                        fup_copy(&v, sizeof(v));
                        v = endian_swap(v, be64toh, htobe64);
                        fprintf(fp, "%"PRId64, v);
                }
                break;
                case 'Q':
                {
                        uint64_t v;
                        fup_copy(&v, sizeof(v));
                        v = endian_swap(v, be64toh, htobe64);
                        fprintf(fp, "%"PRIu64, v);
                }
                break;
                case 'c':
                        fprintf(fp, "%c", (int)*b);
                        b++;
                        break;
                case 's':
                {
                        fprintf(fp, "%.*s", (int)remaining, b);
                        b += remaining;
                }
                break;
                case '$':
                {
                        if (remaining > 0) {
                                snprintf(errstr, errstr_size,
                                         "expected %s end-of-input, "
                                         "but %d bytes remaining",
                                         what, (int)remaining);
                                return -1;
                        }
                }
                break;

                default:
                        KC_FATAL("Invalid pack-format token '%c'", (int)*f);
                        break;

                }

                f++;
        }

        /* Ignore remaining input bytes, if any. */
        return 0;

#undef endian_swap
#undef fup_copy
}

static void fmt_msg_output_str (FILE *fp,
                                const rd_kafka_message_t *rkmessage) {
        int i;
        char errstr[256];

        *errstr = '\0';

        for (i = 0 ; i < conf.fmt_cnt ; i++) {
                int r = 1;
                uint32_t belen;
                const char *what_failed = "";

                switch (conf.fmt[i].type)
                {
                case KC_FMT_OFFSET:
                        r = fprintf(fp, "%"PRId64, rkmessage->offset);
                        break;

                case KC_FMT_KEY:
                        if (rkmessage->key_len) {
                                if (conf.flags & CONF_F_FMT_AVRO_KEY) {
#if ENABLE_AVRO
                                        char *json = kc_avro_to_json(
                                                rkmessage->key,
                                                rkmessage->key_len,
                                                NULL,
                                                errstr, sizeof(errstr));

                                        if (!json) {
                                                what_failed =
                                                        "Avro/Schema-registry "
                                                        "key deserialization";
                                                goto fail;
                                        }

                                        r = fprintf(fp, "%s", json);
                                        free(json);
#else
                                        KC_FATAL("NOTREACHED");
#endif
                                } else if (conf.pack[KC_MSG_FIELD_KEY]) {
                                        if (unpack(fp,
                                                   "key",
                                                   conf.pack[KC_MSG_FIELD_KEY],
                                                   rkmessage->key,
                                                   rkmessage->key_len,
                                                   errstr, sizeof(errstr)) ==
                                            -1)
                                                goto fail;
                                } else
                                        r = fwrite(rkmessage->key,
                                                   rkmessage->key_len, 1, fp);

                        } else if (conf.flags & CONF_F_NULL)
                                r = fwrite(conf.null_str,
                                           conf.null_str_len, 1, fp);

                        break;

                case KC_FMT_KEY_LEN:
                        r = fprintf(fp, "%zd",
                                    /* Use -1 to indicate NULL keys */
                                    rkmessage->key ? (ssize_t)rkmessage->key_len : -1);
                        break;

                case KC_FMT_PAYLOAD:
                        if (rkmessage->len) {
                                if (conf.flags & CONF_F_FMT_AVRO_VALUE) {
#if ENABLE_AVRO
                                        char *json = kc_avro_to_json(
                                                rkmessage->payload,
                                                rkmessage->len,
                                                NULL,
                                                errstr, sizeof(errstr));

                                        if (!json) {
                                                what_failed =
                                                        "Avro/Schema-registry "
                                                        "message "
                                                        "deserialization";
                                                goto fail;
                                        }

                                        r = fprintf(fp, "%s", json);
                                        free(json);
#else
                                        KC_FATAL("NOTREACHED");
#endif
                                } else if (conf.pack[KC_MSG_FIELD_VALUE]) {
                                        if (unpack(fp,
                                                   "value",
                                                   conf.pack[KC_MSG_FIELD_VALUE],
                                                   rkmessage->payload,
                                                   rkmessage->len,
                                                   errstr, sizeof(errstr)) ==
                                            -1)
                                                goto fail;
                                } else
                                        r = fwrite(rkmessage->payload,
                                                   rkmessage->len, 1, fp);

                        } else if (conf.flags & CONF_F_NULL)
                                r = fwrite(conf.null_str,
                                           conf.null_str_len, 1, fp);
                        break;

                case KC_FMT_PAYLOAD_LEN:
                        r = fprintf(fp, "%zd",
                                    /* Use -1 to indicate NULL messages */
                                    rkmessage->payload ? (ssize_t)rkmessage->len : -1);
                        break;

                case KC_FMT_PAYLOAD_LEN_BINARY:
                        /* Use -1 to indicate NULL messages */
                        belen = htobe32((uint32_t)(rkmessage->payload ?
                                                   (ssize_t)rkmessage->len :
                                                   -1));
                        r = fwrite(&belen, sizeof(uint32_t), 1, fp);
                        break;

                case KC_FMT_STR:
                        r = fwrite(conf.fmt[i].str, conf.fmt[i].str_len, 1, fp);
                        break;

                case KC_FMT_TOPIC:
                        r = fprintf(fp, "%s",
                                    rd_kafka_topic_name(rkmessage->rkt));
                        break;

                case KC_FMT_PARTITION:
                        r = fprintf(fp, "%"PRId32, rkmessage->partition);
                        break;

                case KC_FMT_TIMESTAMP:
                {
#if RD_KAFKA_VERSION >= 0x000902ff
                        rd_kafka_timestamp_type_t tstype;
                        r = fprintf(fp, "%"PRId64,
                                    rd_kafka_message_timestamp(rkmessage,
                                                               &tstype));
#else
                        r = fprintf(fp, "-1");
#endif
                        break;
                }

                case KC_FMT_HEADERS:
                {
#if HAVE_HEADERS
                        rd_kafka_headers_t *hdrs;
                        rd_kafka_resp_err_t err;

                        err = rd_kafka_message_headers(rkmessage, &hdrs);
                        if (err == RD_KAFKA_RESP_ERR__NOENT) {
                                r = 1; /* Fake it to continue */
                        } else if (err != RD_KAFKA_RESP_ERR_NO_ERROR) {
                                what_failed = "Failed to parse headers";
                                snprintf(errstr, sizeof(errstr), "%s",
                                         rd_kafka_err2str(err));
                                goto fail;
                        } else {
                                r = print_headers(fp, hdrs);
                        }
#endif
                        break;
                }
                }


                if (r < 1)
                        KC_FATAL("Write error for message "
                                 "of %zd bytes in %s [%"PRId32"] "
                                 "at offset %"PRId64": %s",
                                 rkmessage->len,
                                 rd_kafka_topic_name(rkmessage->rkt),
                                 rkmessage->partition,
                                 rkmessage->offset,
                                 strerror(errno));

                continue;

        fail:
                KC_ERROR("Failed to format message in %s [%"PRId32"] "
                         "at offset %"PRId64": %s%s%s",
                         rd_kafka_topic_name(rkmessage->rkt),
                         rkmessage->partition,
                         rkmessage->offset,
                         what_failed, *what_failed ? ": " : "",
                         errstr);
                return;
        }

}

void fmt_msg_output (FILE *fp, const rd_kafka_message_t *rkmessage) {

#if ENABLE_JSON
        if (conf.flags & CONF_F_FMT_JSON)
                fmt_msg_output_json(fp, rkmessage);
        else
#endif
                fmt_msg_output_str(fp, rkmessage);

}

void buf_destroy (struct buf *b) {
#ifdef MREMAP_MAYMOVE
        munmap(b->buf, b->size);
#else
        free(b->buf);
#endif

        free(b);
}

static struct buf *buf_new (void *buf, size_t size) {
        struct buf *b;
        b = malloc(sizeof(*b));

        b->buf = buf;
        b->size = size;

        return b;
}

void inbuf_destroy (struct inbuf *inbuf) {

        if (inbuf->buf) {
#ifdef MREMAP_MAYMOVE
                munmap(inbuf->buf, inbuf->size);
#else
                free(inbuf->buf);
#endif
        }
}

static size_t inbuf_get_alloc_size (const struct inbuf *inbuf,
                                    size_t min_size) {
        const size_t max_size =
#ifdef MREMAP_MAYMOVE
                   4096
#else
                   1024
#endif
                ;

        if (inbuf->max_size < min_size)
                KC_FATAL("Invalid allocation size: %"PRIu64,
                         (uint64_t)min_size);

        return MAX(min_size, max_size);
}

void inbuf_free_buf (void *buf, size_t size) {
#ifdef MREMAP_MAYMOVE
        munmap(buf, size);
#else
        free(buf);
#endif
}

static char *inbuf_alloc_buf (size_t size) {
        void *p;

#ifdef MREMAP_MAYMOVE
        p = mmap(NULL, size, PROT_READ|PROT_WRITE, MAP_ANONYMOUS, -1, 0);
        if (!p)
                KC_FATAL("Failed to allocate(map) input buffer of %"
                         PRIu64" bytes: %s",
                         size, strerror(errno));
#else
        p = malloc(size);
        if (!p)
                KC_FATAL("Failed to allocate(malloc) input buffer of %"
                         PRIu64" bytes: %s",
                         size, strerror(errno));
#endif

        return (char *)p;
}

static void inbuf_grow (struct inbuf *inbuf, size_t min_size) {
        size_t new_size;
        size_t req_size = inbuf->size + min_size;
        void *p;
#ifdef MREMAP_MAYMOVE
        float multiplier = 1.75;
#else
        float multiplier = 7.9;  /* Keep down the number of reallocs */
#endif

        new_size = MIN(inbuf->max_size, (size_t)((float)req_size * multiplier));

        if (new_size < req_size)
                KC_FATAL("Input is too large, maximum size is %"PRIu64,
                         inbuf->max_size);

#ifdef MREMAP_MAYMOVE
        p = mremap((void *)inbuf->buf, inbuf->size, new_size, MREMAP_MAYMOVE);
        if (p == MAP_FAILED)
                KC_FATAL("Failed to allocate(mremap) input buffer of size "
                         "%"PRIu64" bytes: %s",
                         (uint64_t)new_size, strerror(errno));

#else
        p = realloc(inbuf->buf, new_size);
        if (!p)
                KC_FATAL("Failed to allocate(realloc) input buffer of size "
                         "%"PRIu64" bytes: %s",
                         (uint64_t)new_size, strerror(errno));
#endif

        inbuf->buf = (char *)p;
        inbuf->size = new_size;
}

void inbuf_init (struct inbuf *inbuf, size_t max_size,
                 const char *delim, size_t delim_size) {
        memset(inbuf, 0, sizeof(*inbuf));

        inbuf->max_size = max_size + delim_size;

        inbuf->delim = delim;
        inbuf->dsize = delim_size;
        inbuf->sof = inbuf->dsize - 1;

        inbuf_grow(inbuf, inbuf_get_alloc_size(inbuf, 0));
}

static size_t inbuf_ensure (struct inbuf *inbuf, size_t min_size) {
        size_t remaining = inbuf->size - inbuf->len;

        if (remaining > min_size)
                return remaining;

        inbuf_grow(inbuf, min_size);

        return inbuf->size - inbuf->len;
}

static int inbuf_scan (struct inbuf *inbuf, size_t *dofp) {
        const char *dstart = inbuf->delim;
        const char *dend = inbuf->delim + inbuf->dsize - 1;
        const char *t;

        if (inbuf->len < inbuf->sof)
                return 0; /* Input buffer smaller than delimiter. */

        /* Use Boyer-Moore inspired scan by matching the delimiter from
         * right-to-left. */
        while (inbuf->sof < inbuf->len &&
               (t = (const char *)memchr((void *)(inbuf->buf + inbuf->sof),
                                         (int)*dend,
                                         inbuf->len - inbuf->sof))) {
                /* Found delimiter's last byte and we know that there's at
                 * least the delimiter's size of data to left, so start
                 * scanning backwards. */
                const char *p = t;    /* buffer pointer */
                const char *d = dend; /* delimiter pointer */

                do {
                        d--;
                        p--;
                } while (d >= dstart && *d == *p);

                if (d < dstart) {
                        /* Found a full delimiter. */
                        *dofp = (size_t)(p+1 - inbuf->buf);
                        return 1;
                }

                /* Incomplete delimiter, scan forward. */
                inbuf->sof = (size_t)(t - inbuf->buf) + 1;
        }

        return 0;
}

static void inbuf_split (struct inbuf *inbuf, size_t dof,
                         char **outp, size_t *out_sizep) {
        size_t nof = dof + inbuf->dsize;
        size_t remaining = inbuf->len - nof;
        void *rbuf = NULL;
        size_t rsize = 0;

        /* Copy right side of buffer (past the delimiter) to a temporary
         * buffer that will be stored on inbuf when the left side is extracted.
         */
        rsize = inbuf_get_alloc_size(inbuf, remaining);
        rbuf = inbuf_alloc_buf(rsize);
        if (remaining > 0)
                memcpy(rbuf, inbuf->buf+nof, remaining);

        /* Shrink the returned buffer to the actual size of the left side. */
        if (remaining + inbuf->dsize > 4096/2) {
#ifdef MREMAP_MAYMOVE
                *outp = mremap((void *)inbuf->buf, inbuf->size, dof,
                               MREMAP_MAYMOVE);
                if (!*outp)
                        KC_FATAL("Failed to shrink(mremap) buffer to %"
                                 PRIu64" bytes: %s",
                                 (uint64_t)dof, strerror(errno));
#else
                *outp = realloc((void *)inbuf->buf, MAX(dof, 16));
                if (!*outp)
                        KC_FATAL("Failed to shrink(REALLOC) buffer to %"
                                 PRIu64" bytes: %s",
                                 (uint64_t)dof, strerror(errno));
#endif
        } else {
                *outp = inbuf->buf;
        }


        *out_sizep = dof;


        /* Set up a new (or the remaining) input buffer. */
        inbuf->buf = rbuf;
        inbuf->size = rsize;
        inbuf->len = remaining;
        inbuf->sof = inbuf->dsize - 1;
}

int inbuf_read_to_delimeter (struct inbuf *inbuf, FILE *fp,
                             struct buf **outbuf) {
        int read_size = MIN(1024, inbuf->max_size);
        int fd = fileno(fp);
        fd_set readfds;

        /*
         * 1. Make sure there is enough output buffer room for read_size.
         * 2. Read up to read_size from input stream.
         * 3. Scan output buffer from current scan position for delimiter using
         *    Boyer-Moore (searched right-to-left).
         * 4. If delimiter is not found, go to 1.
         * 5. Skip delimiter and copy remaining buffer to new buffer.
         * 6. Return original buffer to caller.
         */

        if (!inbuf->buf)
                return 0;  /* Previous EOF encountered, see below. */

        while (conf.run) {
                ssize_t r;
                size_t dof;
                int delim_found;

                /* Scan for delimiter */
                delim_found = inbuf_scan(inbuf, &dof);

                if (delim_found) {
                        char *buf;
                        size_t size;

                        /* Delimiter found, split and return. */
                        inbuf_split(inbuf, dof, &buf, &size);

                        *outbuf = buf_new(buf, size);
                        return 1;
                }

                inbuf_ensure(inbuf, read_size);

                FD_ZERO(&readfds);
                FD_SET(fd, &readfds);
                select(1, &readfds, NULL, NULL, NULL);

                if (FD_ISSET(fd, &readfds))
                        r = read(fd, inbuf->buf+inbuf->len, read_size);
                else
                        r = 0;

                if (r <= 0) {
                        if (inbuf->len == 0) {
                                /* EOF with no accumulated data */
                                inbuf_destroy(inbuf);
                                return 0;
                        } else {
                                /* EOF but we have accumulated data, return what
                                 * we have. */
                                dof = inbuf->len;
                                *outbuf = buf_new(inbuf->buf, inbuf->len);
                                inbuf->buf = NULL;
                                return 1;
                        }
                }

                inbuf->len += (size_t)r;

        }

        return 0; /* NOTREACHED */
}

void fmt_msg_output_json (FILE *fp, const rd_kafka_message_t *rkmessage) {
        yajl_gen g;
        const char *topic = rd_kafka_topic_name(rkmessage->rkt);
        const unsigned char *buf;
        size_t len;

        g = yajl_gen_alloc(NULL);

        yajl_gen_map_open(g);
        JS_STR(g, "topic");
        JS_STR(g, topic);

        JS_STR(g, "partition");
        yajl_gen_integer(g, (int)rkmessage->partition);

        JS_STR(g, "offset");
        yajl_gen_integer(g, (long long int)rkmessage->offset);

#if RD_KAFKA_VERSION >= 0x000902ff
        {
                rd_kafka_timestamp_type_t tstype;
                int64_t ts = rd_kafka_message_timestamp(rkmessage, &tstype);
                if (tstype != RD_KAFKA_TIMESTAMP_NOT_AVAILABLE) {
                        JS_STR(g, "tstype");
                        if (tstype == RD_KAFKA_TIMESTAMP_CREATE_TIME)
                                JS_STR(g, "create");
                        else if (tstype == RD_KAFKA_TIMESTAMP_LOG_APPEND_TIME)
                                JS_STR(g, "logappend");
                        else
                                JS_STR(g, "unknown");
                        JS_STR(g, "ts");
                        yajl_gen_integer(g, (long long int)ts);
                }
        }
#else
        JS_STR(g, "tstype");
        JS_STR(g, "unknown");
        JS_STR(g, "ts");
        yajl_gen_integer(g, 0);
#endif

        JS_STR(g, "broker");
#if RD_KAFKA_VERSION >= 0x010500ff
        yajl_gen_integer(g, (int)rd_kafka_message_broker_id(rkmessage));
#else
        yajl_gen_integer(g, -1);
#endif


#if HAVE_HEADERS
        {
                rd_kafka_headers_t *hdrs;

                if (!rd_kafka_message_headers(rkmessage, &hdrs)) {
                        size_t idx = 0;
                        const char *name;
                        const void *value;
                        size_t size;

                        JS_STR(g, "headers");
                        yajl_gen_array_open(g);

                        while (!rd_kafka_header_get_all(hdrs, idx++, &name,
                                                        &value, &size)) {
                                JS_STR(g, name);
                                if (value)
                                        yajl_gen_string(g, value, size);
                                else
                                        yajl_gen_null(g);
                        }

                        yajl_gen_array_close(g);
                }
        }
#endif


        JS_STR(g, "key");
        if (rkmessage->key) {
#if ENABLE_AVRO && YAJL_HAS_GEN_VERBATIM
                if (conf.flags & CONF_F_FMT_AVRO_KEY) {
                        char errstr[256];
                        int schema_id = -1;
                        char *json = kc_avro_to_json(
                                rkmessage->key,
                                rkmessage->key_len,
                                &schema_id,
                                errstr, sizeof(errstr));

                        if (!json) {
                                KC_ERROR("Failed to deserialize key in "
                                         "message in %s [%"PRId32"] at "
                                         "offset %"PRId64": %s",
                                         rd_kafka_topic_name(rkmessage->rkt),
                                         rkmessage->partition,
                                         rkmessage->offset, errstr);
                                yajl_gen_null(g);
                                JS_STR(g, "key_error");
                                JS_STR(g, errstr);
                        } else {
                                yajl_gen_verbatim(g, json, strlen(json));
                                JS_STR(g, "key_schema_id");
                                JS_INT(g, schema_id);
                        }
                        free(json);
                } else
#endif
                        yajl_gen_string(g,
                                        (const unsigned char *)rkmessage->key,
                                        rkmessage->key_len);
        } else
                yajl_gen_null(g);

        JS_STR(g, "payload");
        if (rkmessage->payload) {
#if ENABLE_AVRO && YAJL_HAS_GEN_VERBATIM
                if (conf.flags & CONF_F_FMT_AVRO_VALUE) {
                        char errstr[256];
                        int schema_id = -1;
                        char *json = kc_avro_to_json(
                                rkmessage->payload,
                                rkmessage->len,
                                &schema_id,
                                errstr, sizeof(errstr));

                        if (!json) {
                                KC_ERROR("Failed to deserialize value in "
                                         "message in %s [%"PRId32"] at "
                                         "offset %"PRId64": %s",
                                         rd_kafka_topic_name(rkmessage->rkt),
                                         rkmessage->partition,
                                         rkmessage->offset, errstr);
                                yajl_gen_null(g);
                                JS_STR(g, "payload_error");
                                JS_STR(g, errstr);
                        } else {
                                yajl_gen_verbatim(g, json, strlen(json));
                                JS_STR(g, "value_schema_id");
                                JS_INT(g, schema_id);
                        }

                        free(json);
                } else
#endif
                        yajl_gen_string(g,
                                        (const unsigned char *)
                                        rkmessage->payload,
                                        rkmessage->len);
        } else
                yajl_gen_null(g);

        yajl_gen_map_close(g);

        yajl_gen_get_buf(g, &buf, &len);

        if (fwrite(buf, len, 1, fp) != 1 ||
            (conf.fmt[0].str_len > 0 &&
             fwrite(conf.fmt[0].str, conf.fmt[0].str_len, 1, fp) != 1))
                KC_FATAL("Output write error: %s", strerror(errno));

        yajl_gen_free(g);
}

void metadata_print_json (const struct rd_kafka_metadata *metadata,
                          int32_t controllerid) {
        yajl_gen g;
        int i, j, k;
        const unsigned char *buf;
        size_t len;

        g = yajl_gen_alloc(NULL);

        yajl_gen_map_open(g);

        JS_STR(g, "originating_broker");
        yajl_gen_map_open(g);
        JS_STR(g, "id");
        yajl_gen_integer(g, (long long int)metadata->orig_broker_id);
        JS_STR(g, "name");
        JS_STR(g, metadata->orig_broker_name);
        yajl_gen_map_close(g);


        JS_STR(g, "query");
        yajl_gen_map_open(g);
        JS_STR(g, "topic");
        JS_STR(g, conf.topic ? : "*");
        yajl_gen_map_close(g);

        JS_STR(g, "controllerid");
        yajl_gen_integer(g, (long long int)controllerid);

        /* Iterate brokers */
        JS_STR(g, "brokers");
        yajl_gen_array_open(g);
        for (i = 0 ; i < metadata->broker_cnt ; i++) {
                int blen = strlen(metadata->brokers[i].host);
                char *host = alloca(blen+1+5+1);
                sprintf(host, "%s:%i",
                        metadata->brokers[i].host, metadata->brokers[i].port);

                yajl_gen_map_open(g);

                JS_STR(g, "id");
                yajl_gen_integer(g, (long long int)metadata->brokers[i].id);

                JS_STR(g, "name");
                JS_STR(g, host);

                yajl_gen_map_close(g);
        }
        yajl_gen_array_close(g);

        /* Iterate topics */
        JS_STR(g, "topics");
        yajl_gen_array_open(g);
        for (i = 0 ; i < metadata->topic_cnt ; i++) {
                const struct rd_kafka_metadata_topic *t = &metadata->topics[i];

                yajl_gen_map_open(g);
                JS_STR(g, "topic");
                JS_STR(g, t->topic);

                if (t->err) {
                        JS_STR(g, "error");
                        JS_STR(g, rd_kafka_err2str(t->err));
                }

                JS_STR(g, "partitions");
                yajl_gen_array_open(g);

                /* Iterate topic's partitions */
                for (j = 0 ; j < t->partition_cnt ; j++) {
                        const struct rd_kafka_metadata_partition *p;
                        p = &t->partitions[j];

                        yajl_gen_map_open(g);

                        JS_STR(g, "partition");
                        yajl_gen_integer(g, (long long int)p->id);

                        if (p->err) {
                                JS_STR(g, "error");
                                JS_STR(g, rd_kafka_err2str(p->err));
                        }

                        JS_STR(g, "leader");
                        yajl_gen_integer(g, (long long int)p->leader);

                        /* Iterate partition's replicas */
                        JS_STR(g, "replicas");
                        yajl_gen_array_open(g);
                        for (k = 0 ; k < p->replica_cnt ; k++) {
                                yajl_gen_map_open(g);
                                JS_STR(g, "id");
                                yajl_gen_integer(g,
                                                 (long long int)p->replicas[k]);
                                yajl_gen_map_close(g);
                        }
                        yajl_gen_array_close(g);


                        /* Iterate partition's ISRs */
                        JS_STR(g, "isrs");
                        yajl_gen_array_open(g);
                        for (k = 0 ; k < p->isr_cnt ; k++) {
                                yajl_gen_map_open(g);
                                JS_STR(g, "id");
                                yajl_gen_integer(g, (long long int)p->isrs[k]);
                                yajl_gen_map_close(g);
                        }
                        yajl_gen_array_close(g);

                        yajl_gen_map_close(g);

                }
                yajl_gen_array_close(g);

                yajl_gen_map_close(g);
        }
        yajl_gen_array_close(g);

        yajl_gen_map_close(g);

        yajl_gen_get_buf(g, &buf, &len);

        if (fwrite(buf, len, 1, stdout) != 1)
                KC_FATAL("Output write error: %s", strerror(errno));

        yajl_gen_free(g);
}

void partition_list_print_json (const rd_kafka_topic_partition_list_t *parts,
                                void *json_gen) {
        yajl_gen g = (yajl_gen)json_gen;
        int i;
        const char *last_topic = "";

        if (!g)
                g = yajl_gen_alloc(NULL);

        yajl_gen_map_open(g);
        for (i = 0 ; i < parts->cnt ; i++) {
                const rd_kafka_topic_partition_t *p = &parts->elems[i];
                char partstr[16];

                if (strcmp(last_topic, p->topic)) {
                        if (*last_topic)
                                yajl_gen_map_close(g); /* topic */

                        JS_STR(g, p->topic);
                        yajl_gen_map_open(g); /* topic */
                        JS_STR(g, "topic");
                        JS_STR(g, p->topic);
                        last_topic = p->topic;
                }

                snprintf(partstr, sizeof(partstr), "%"PRId32, p->partition);

                JS_STR(g, partstr);
                yajl_gen_map_open(g);
                JS_STR(g, "partition");
                yajl_gen_integer(g, p->partition);
                JS_STR(g, "offset");
                yajl_gen_integer(g, p->offset);
                if (p->err) {
                        JS_STR(g, "error");
                        JS_STR(g, rd_kafka_err2str(p->err));
                }
                yajl_gen_map_close(g);

        }

        if (*last_topic)
                yajl_gen_map_close(g); /* topic */

        yajl_gen_map_close(g);


        if (!json_gen) {
                const unsigned char *buf;
                size_t len;

                yajl_gen_get_buf(g, &buf, &len);
                (void)fwrite(buf, len, 1, stdout);
                yajl_gen_free(g);
        }
}

